func (p *Pool) worker(ctx context.Context) {
    defer p.wg.Done()
    for {
        select {
        case <-ctx.Done():
            return
        case job, ok := <-p.jobs:
            if !ok {
                return
            }
            func() {
                defer func() {
                    if r := recover(); r != nil {
                        p.logger.Error("worker panic", "recover", r)
                    }
                }()
                if err := job(ctx); err != nil {
                    p.logger.Error("job error", "err", err)
                }
            }()
        }
    }
}
